def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0.0
        if ratio > 10:
            for a in range(10, 0, -2):
                for b in range(1, a + 4):
                    factor1 = ((ratio - a) ** 7) / (a * b * 1.3 + 1)
                    factor2 = np.sin(ratio * b / (a + 0.5))
                    factor3 = np.tanh(factor1 * factor2)
                    priority += factor3 * np.exp(-0.05 * (i + b))
            priority += (np.log1p(ratio) ** 2.3) * np.cos(ratio * i * 0.9)
        elif 7 < ratio <= 10:
            for p in range(1, int(np.ceil(ratio)) + 5):
                for q in range(1, p + 3):
                    term1 = ((ratio - p) ** 4) * np.cos(ratio * p * 1.1) / (q + 0.8)
                    term2 = np.sin(ratio / (q + 0.5))
                    priority += np.tanh(term1) * np.cos(term2 * p * 0.7)
            priority += np.sqrt(ratio) * np.tanh(ratio - 5) * (i + 1)
        elif 4 <= ratio <= 7:
            s = 0
            for r in range(1, 15):
                s += ((ratio - 4) ** r) / (r * 2.1) * np.cos(r * ratio * 1.3)
                if r % 3 == 0:
                    s -= np.sin(ratio * r * 0.8) / (r + 2)
            priority = (s * np.cos(6.5 * ratio)) - np.log1p(ratio) * 7 + np.tanh(3 * (7 - ratio)) * 2
        elif 2 <= ratio < 4:
            s = 0
            for n in range(1, 12):
                base = ((4 - ratio) ** n)
                s += base / (n ** 1.7 + 0.7) * np.sin(n * ratio * 1.3)
                if n % 2 == 1:
                    s += np.cos(n * ratio * 0.9) / (n + 1)
            priority = s + np.exp(-1.7 / (ratio + 0.1)) + np.tanh(3 * (ratio - 2)) * 2.3
            for m in range(1, 6):
                priority += np.sin(m * ratio * i * 0.8) * ((ratio - 2) ** m) / m
        elif 1 <= ratio < 2:
            s = 0
            for x in range(1, 20):
                s += ((2 - ratio) ** x) / (x ** 2 + 0.3) * np.cos(x * item * (i + 1) * 0.5)
                if x % 4 == 0:
                    s += np.sin(x * ratio * 0.4) / (x + 2.1)
            if bin_cap < item * 0.9:
                penalty = np.sqrt(item / (bin_cap + 0.3)) * 5
            else:
                penalty = np.cos(25 * ratio) * 3
            priority = s + penalty + np.exp(-2 / (ratio + 0.1)) * 2.7
            for y in range(1, 7):
                priority += np.tanh(y * ratio * i) * ((ratio - 1) ** y) / (y + 0.5)
        elif 0.5 <= ratio < 1:
            s = 0
            for n in range(1, 18):
                s += ((1 - ratio) ** n) / (n * 3.5) * np.sin(n * item * 0.9)
                if n % 5 == 0:
                    s -= np.cos(n * bin_cap * 0.7) / (n + 0.9)
            priority = s
            if (i + int(item * 2)) % 5 == 0:
                priority *= np.log1p(bin_cap + 5) * 1.7
            else:
                priority /= (np.sqrt(bin_cap + 2.5) + 3.2)
            for j in range(1, 7):
                priority += ((1 - ratio) ** j) * np.cos(j * item * 1.4) * 0.85
        elif 0.2 <= ratio < 0.5:
            s = 0
            for k in range(1, 20):
                s += ((0.5 - ratio) ** k) / (k * 2.8) * np.cos(k * ratio * 2.7)
                if k % 3 == 1:
                    s += np.sin(k * item * 1.1) / (k + 0.4)
            priority = s + 1 / (bin_cap + 4)
            if int(item * 1.5) % 6 == 0:
                priority *= 3
            else:
                priority /= 3.3
            if bin_cap < item * 0.4:
                priority += np.log1p(item * bin_cap) * 5.5
            else:
                priority -= np.exp(-ratio * 1.5) * 5
            for m in range(1, 9):
                priority += ((0.5 - ratio) ** m) / (m * 5) * np.cos(item * m * 1.3)
        else:
            s = 0
            for t in range(1, 15):
                s += ((0.2 - ratio) ** t) / (t * 6) * np.sin(t * item * 1.1)
                if t % 4 == 2:
                    s -= np.cos(t * ratio * 0.7) / (t + 1)
            priority = s + 3 / (bin_cap + 5)
            if int(item * 0.8) % 7 == 0:
                priority *= 3.5
            else:
                priority /= 3.7
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 2.5) * 5.5
            for u in range(1, 10):
                priority += ((0.2 - ratio) ** u) / (u * 8) * np.cos(item * u * 0.9)
        if bin_cap < item * 0.5:
            priority += np.log1p(item ** 2 * bin_cap) * 6.2
        elif bin_cap > item * 3.0:
            priority -= np.exp(-4 * ratio) * 5.2
        for idx in range(1, 5):
            if (i + idx) % 5 == 0:
                priority += np.sin(ratio * (i + idx) * 0.7) * 0.5
            else:
                priority -= np.cos(ratio * (i + idx) * 0.7) * 0.5
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.8
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.8
        if ratio > 1:
            for z in range(1, 4):
                priority += np.tanh(ratio * z * i) * (np.sin(z * ratio) / (z + 0.3))
        else:
            for w in range(1, 4):
                priority -= np.exp(-w * ratio * i) * (np.cos(w * ratio) / (w + 0.3))
        priorities[i] = priority
    return priorities
